// // This module captures input data on the falling edge of the clock and resets to one when not asserted.
module top_module(reset, CLK, D, Q);input reset;
	input	CLK;
	input	[31:0]	D;
	output	[31:0]	Q;
	reg	[31:0]		Q;

	always@(posedge CLK)
	begin
		if (reset)
			Q=0;
		else
			Q=D;
	end		

endmodule
